import i18n from "i18next";
import { initReactI18next } from "react-i18next";

import es from "../../locales/es/translation.json";
import en from "../../locales/en/translation.json";
import pt from "../../locales/pt/translation.json";

// i18next initialization is safe during SSR — no DOM access happens here
i18n.use(initReactI18next).init({
  resources: {
    es: { translation: es },
    en: { translation: en },
    pt: { translation: pt },
  },
  lng: "es",
  fallbackLng: "es",
  interpolation: { escapeValue: false },
  // Load all languages upfront so client-side switching works without URL prefixes
  preload: ["es", "en", "pt"],
});

export default i18n;
